solution_code:
#include <iostream>
#include <string>

int main() {
    std::string first;
    std::string last;
    std::cin >> first;
    std::cin >> last;
    std::string full = first + " " + last;
    std::cout << "Full name: " << full << "\n";
    std::cout << "Characters: " << full.length() << "\n";
    return 0;
}

